import { Fixture } from "../../objects/fixture";

interface SeasonSummaryComponentProps{
    fixtures : Fixture[]
}

const SeasonSummary = ({fixtures} : SeasonSummaryComponentProps) => {  

    const totalGames = fixtures.length;
    const totalWins = fixtures.filter(fixture => fixture.result === 0).length;
    const totalDraws = fixtures.filter(fixture => fixture.result === 1).length;
    const totalLosses = fixtures.filter(fixture => fixture.result === 2).length;
    const glsFor = fixtures.filter(fixture => fixture.glsFor).reduce((sum, currentValue) => sum + currentValue.glsFor, 0);
    const glsAgainst = fixtures.filter(fixture => fixture.glsA).reduce((sum, currentValue) => sum + currentValue.glsA, 0);
    const goalDifference = glsFor - glsAgainst;
    const totalPoints = fixtures.filter(fixture => fixture.pts).reduce((sum, currentValue) => sum + currentValue.pts, 0);

    return (  
        <div>
        <table>
            <thead>
                <tr>
                    <td>PLD</td>
                    <td>W</td>
                    <td>L</td>
                    <td>D</td>
                    <td>GF</td>
                    <td>GA</td>
                    <td>GD</td>
                    <td>Pts</td>
                </tr>
            </thead>
            <tbody>
            <tr>
                <td>{totalGames}</td>
                <td>{totalWins}</td>
                <td>{totalDraws}</td>
                <td>{totalLosses}</td>
                <td>{glsFor}</td>     
                <td>{glsAgainst}</td>       
                <td>{goalDifference}</td>
                <td>{totalPoints}</td>
            </tr>  
            </tbody>        
        </table>
        </div>  
    );

}
export default SeasonSummary;
